# Azioni Rapide Firewall

## Operazioni Bulk

<button onclick="toggleAllRules(true)" style="background-color: #28a745; color: white; padding: 10px 20px; border: none; border-radius: 4px; margin: 5px; cursor: pointer;">✅ Attiva Tutte le Regole</button>

<button onclick="toggleAllRules(false)" style="background-color: #dc3545; color: white; padding: 10px 20px; border: none; border-radius: 4px; margin: 5px; cursor: pointer;">❌ Disattiva Tutte le Regole</button>

<button onclick="reloadFirewallRules()" style="background-color: #007bff; color: white; padding: 10px 20px; border: none; border-radius: 4px; margin: 5px; cursor: pointer;">🔄 Ricarica Regole</button>

<button onclick="backupRules()" style="background-color: #6c757d; color: white; padding: 10px 20px; border: none; border-radius: 4px; margin: 5px; cursor: pointer;">💾 Backup Regole</button>

## Filtri Rapidi

<select id="interfaceFilter" onchange="filterRules()" style="padding: 8px; margin: 5px; border: 1px solid #ccc; border-radius: 4px;">
  <option value="">Tutte le Interfacce</option>
  <option value="wan">WAN</option>
  <option value="lan">LAN</option>
  <option value="opt1">OPT1</option>
  <option value="opt2">OPT2</option>
</select>

<select id="actionFilter" onchange="filterRules()" style="padding: 8px; margin: 5px; border: 1px solid #ccc; border-radius: 4px;">
  <option value="">Tutte le Azioni</option>
  <option value="pass">PASS</option>
  <option value="block">BLOCK</option>
  <option value="reject">REJECT</option>
</select>

<select id="statusFilter" onchange="filterRules()" style="padding: 8px; margin: 5px; border: 1px solid #ccc; border-radius: 4px;">
  <option value="">Tutti gli Stati</option>
  <option value="enabled">Solo Attive</option>
  <option value="disabled">Solo Disattive</option>
</select>

<script>
function toggleAllRules(enable) {
    const action = enable ? 'enable' : 'disable';
    fetch('/api/v1/firewall/rules/bulk/' + action, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': 'Bearer ' + localStorage.getItem('jwt_token')
        }
    })
    .then(response => response.json())
    .then(data => {
        alert(action.toUpperCase() + ' completed: ' + data.message);
        location.reload();
    })
    .catch(error => {
        console.error('Error:', error);
        alert('Errore durante l\'operazione');
    });
}

function reloadFirewallRules() {
    fetch('/api/v1/firewall/reload', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': 'Bearer ' + localStorage.getItem('jwt_token')
        }
    })
    .then(response => response.json())
    .then(data => {
        alert('Regole ricaricate: ' + data.message);
    })
    .catch(error => {
        console.error('Error:', error);
        alert('Errore durante il reload');
    });
}

function backupRules() {
    fetch('/api/v1/firewall/backup', {
        method: 'GET',
        headers: {
            'Authorization': 'Bearer ' + localStorage.getItem('jwt_token')
        }
    })
    .then(response => response.blob())
    .then(blob => {
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.style.display = 'none';
        a.href = url;
        a.download = 'firewall_rules_backup_' + new Date().toISOString().split('T')[0] + '.json';
        document.body.appendChild(a);
        a.click();
        window.URL.revokeObjectURL(url);
        alert('Backup scaricato con successo');
    })
    .catch(error => {
        console.error('Error:', error);
        alert('Errore durante il backup');
    });
}

function filterRules() {
    const interface_filter = document.getElementById('interfaceFilter').value;
    const action_filter = document.getElementById('actionFilter').value;
    const status_filter = document.getElementById('statusFilter').value;

    // Implementa il filtro tramite query parameters o aggiorna la tabella
    const params = new URLSearchParams();
    if (interface_filter) params.append('interface', interface_filter);
    if (action_filter) params.append('action', action_filter);
    if (status_filter) params.append('enabled', status_filter === 'enabled');

    // Ricarica il pannello con i filtri applicati
    console.log('Applying filters:', params.toString());
}
</script>
